// MARK: - AES Encryption Engine

final class AESEncryptionEngine {
    
    private let keySize = kCCKeySizeAES256
    private let blockSize = kCCBlockSizeAES128
    private let pbkdfRounds: UInt32 = 100_000
    private let hmacAlgorithm = CCHmacAlgorithm(kCCHmacAlgSHA256)
    private let hmacLength = Int(CC_SHA256_DIGEST_LENGTH)
    
    /// Derives an encryption key from the master key using PBKDF2 with a unique salt
    private func deriveKey(masterKey: Data, salt: Data) throws -> Data {
        var derivedKey = [UInt8](repeating: 0, count: keySize)
        
        let status = masterKey.withUnsafeBytes { masterKeyBytes -> CCCryptorStatus in
            salt.withUnsafeBytes { saltBytes -> CCCryptorStatus in
                guard let masterKeyPtr = masterKeyBytes.baseAddress?.assumingMemoryBound(to: Int8.self),
                      let saltPtr = saltBytes.baseAddress?.assumingMemoryBound(to: UInt8.self) else {
                    return CCCryptorStatus(kCCParamError)
                }
                return CCCryptorStatus(CCKeyDerivationPBKDF(
                    CCPBKDFAlgorithm(kCCPBKDF2),
                    masterKeyPtr,
                    masterKey.count,
                    saltPtr,
                    salt.count,
                    CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA256),
                    pbkdfRounds,
                    &derivedKey,
                    keySize
                ))
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.keyDerivationFailed
        }
        
        return Data(derivedKey)
    }
    
    /// Computes HMAC-SHA256 for authenticated encryption
    private func computeHMAC(data: Data, key: Data) -> Data {
        var hmac = [UInt8](repeating: 0, count: hmacLength)
        
        data.withUnsafeBytes { dataBytes in
            key.withUnsafeBytes { keyBytes in
                guard let dataPtr = dataBytes.baseAddress,
                      let keyPtr = keyBytes.baseAddress else { return }
                CCHmac(hmacAlgorithm, keyPtr, key.count, dataPtr, data.count, &hmac)
            }
        }
        
        return Data(hmac)
    }
    
    /// Constant-time comparison to prevent timing attacks
    private func secureCompare(_ lhs: Data, _ rhs: Data) -> Bool {
        guard lhs.count == rhs.count else { return false }
        var result: UInt8 = 0
        for (a, b) in zip(lhs, rhs) {
            result |= a ^ b
        }
        return result == 0
    }
    
    func encrypt(plaintext: Data, masterKey: Data) throws -> EncryptedPayload {
        let keychainManager = KeychainManager.shared
        
        // Generate random IV and salt for each encryption operation
        let iv = try keychainManager.generateRandomBytes(count: blockSize)
        let salt = try keychainManager.generateRandomBytes(count: 32)
        
        // Derive a unique key for this encryption
        let derivedKey = try deriveKey(masterKey: masterKey, salt: salt)
        
        // Split derived key: first half for encryption, second half for HMAC
        let encryptionKey = derivedKey.prefix(16)
        let hmacKey = derivedKey.suffix(16)
        
        // Re-derive full encryption key from the encryption portion
        let fullEncKey = try deriveKey(masterKey: encryptionKey, salt: salt)
        
        let bufferSize = plaintext.count + blockSize
        var ciphertext = [UInt8](repeating: 0, count: bufferSize)
        var bytesEncrypted = 0
        
        let status = plaintext.withUnsafeBytes { plaintextBytes -> CCCryptorStatus in
            fullEncKey.withUnsafeBytes { keyBytes -> CCCryptorStatus in
                iv.withUnsafeBytes { ivBytes -> CCCryptorStatus in
                    guard let plaintextPtr = plaintextBytes.baseAddress,
                          let keyPtr = keyBytes.baseAddress,
                          let ivPtr = ivBytes.baseAddress else {
                        return CCCryptorStatus(kCCParamError)
                    }
                    return CCCrypt(
                        CCOperation(kCCEncrypt),
                        CCAlgorithm(kCCAlgorithmAES),
                        CCOptions(kCCOptionPKCS7Padding),
                        keyPtr,
                        keySize,
                        ivPtr,
                        plaintextPtr,
                        plaintext.count,
                        &ciphertext,
                        bufferSize,
                        &bytesEncrypted
                    )
                }
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.encryptionFailed(status)
        }
        
        let ciphertextData = Data(ciphertext.prefix(bytesEncrypted))
        
        // Compute HMAC over IV + ciphertext for authenticated encryption (Encrypt-then-MAC)
        var hmacInput = Data()
        hmacInput.append(iv)
        hmacInput.append(ciphertextData)
        let tag = computeHMAC(data: hmacInput, key: hmacKey)
        
        return EncryptedPayload(
            ciphertext: ciphertextData,
            iv: iv,
            salt: salt,
            tag: tag
        )
    }
    
    func decrypt(payload: EncryptedPayload, masterKey: Data) throws -> Data {
        // Derive the same key
        let derivedKey = try deriveKey(masterKey: masterKey, salt: payload.salt)
        
        let encryptionKey = derivedKey.prefix(16)
        let hmacKey = derivedKey.suffix(16)
        
        // Verify HMAC first (Encrypt-then-MAC: verify before decrypting)
        var hmacInput = Data()
        hmacInput.append(payload.iv)
        hmacInput.append(payload.ciphertext)
        let computedTag = computeHMAC(data: hmacInput, key: hmacKey)
        
        guard secureCompare(computedTag, payload.tag) else {
            throw DataSecurityError.decryptionFailed(CCCryptorStatus(kCCAuthFailed))
        }
        
        let fullEncKey = try deriveKey(masterKey: encryptionKey, salt: payload.salt)
        
        let bufferSize = payload.ciphertext.count + blockSize
        var plaintext = [UInt8](repeating: 0, count: bufferSize)
        var bytesDecrypted = 0
        
        let status = payload.ciphertext.withUnsafeBytes { ciphertextBytes -> CCCryptorStatus in
            fullEncKey.withUnsafeBytes { keyBytes -> CCCryptorStatus in
                payload.iv.withUnsafeBytes { ivBytes -> CCCryptorStatus in
                    guard let ciphertextPtr = ciphertextBytes.baseAddress,
                          let keyPtr = keyBytes.baseAddress,
                          let ivPtr = ivBytes.baseAddress else {
                        return CCCryptorStatus(kCCParamError)
                    }
                    return CCCrypt(
                        CCOperation(kCCDecrypt),
                        CCAlgorithm(kCCAlgorithmAES),
                        CCOptions(kCCOptionPKCS7Padding),
                        keyPtr,
                        keySize,
                        ivPtr,
                        ciphertextPtr,
                        payload.ciphertext.count,
                        &plaintext,
                        bufferSize,
                        &bytesDecrypted
                    )
                }
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.decryptionFailed(status)
        }
        
        return Data(plaintext.prefix(bytesDecrypted))
    }
}

