    // MARK: - Password Hashing Utility
    
    /// Hashes a password using PBKDF2 - use this before storing credentials
    func hashPassword(_ password: String) throws -> String {
        let salt = try keychainManager.generateRandomBytes(count: 32)
        let passwordData = Data(password.utf8)
        var hash = [UInt8](repeating: 0, count: 32)
        
        let status = passwordData.withUnsafeBytes { passwordBytes -> CCCryptorStatus in
            salt.withUnsafeBytes { saltBytes -> CCCryptorStatus in
                guard let passwordPtr = passwordBytes.baseAddress?.assumingMemoryBound(to: Int8.self),
                      let saltPtr = saltBytes.baseAddress?.assumingMemoryBound(to: UInt8.self) else {
                    return CCCryptorStatus(kCCParamError)
                }
                return CCCryptorStatus(CCKeyDerivationPBKDF(
                    CCPBKDFAlgorithm(kCCPBKDF2),
                    passwordPtr,
                    passwordData.count,
                    saltPtr,
                    salt.count,
                    CCPseudoRandomAlgorithm(kCCPRFHmacAlgSHA256),
                    200_000,
                    &hash,
                    32
                ))
            }
        }
        
        guard status == kCCSuccess else {
            throw DataSecurityError.keyDerivationFailed
        }
        
        // Return salt:hash as base64
        let saltBase64 = salt.base64EncodedString()
        let hashBase64 = Data(hash).base64EncodedString()
        return "\(saltBase64):\(hashBase64)"
    }
